    } else if (el.kind === 'roof_type') {
      const bucket = (out['roof_type'] ??= []);
      bucket.push({
        id: el.id,
        name: el.name,
        familyName: `${el.layers.length} layers`,
        custom: true,
        kind: 'roof_type',
      });
    }
  }
  return out as Record<FamilyDiscipline, CatalogEntry[]>;
}

